import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './App.css';

const Home = () => {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  // Check for logged-in user on component mount
  useEffect(() => {
    const loggedInUser = localStorage.getItem('user');
    if (loggedInUser) {
      setUser(JSON.parse(loggedInUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
    alert('Logged out successfully');
    navigate('/login');
  };

  return (
    <div className="home-container">
      {/* Header/Navbar Section */}
      <header style={styles.header}>
        <div style={styles.logo}>Dombivli Smart City</div>
        <nav>
          {user ? (
            <div style={styles.userInfo}>
              <span style={styles.welcomeText}>Welcome, {user.name}</span>
              <button onClick={handleLogout} style={styles.logoutBtn}>Logout</button>
            </div>
          ) : (
            <button onClick={() => navigate('/login')} style={styles.loginBtn}>Login</button>
          )}
        </nav>
      </header>

      {/* Main Hero Section */}
      <main style={styles.main}>
        <h1>Smart City Web Portal</h1>
        <p>Providing seamless digital services to the citizens of Dombivli West & KDMC.</p>
        
        <div style={styles.grid}>
          <div style={styles.card} onClick={() => navigate('/services')}>
            <h3>Municipal Services</h3>
            <p>Water, Garbage & Electricity</p>
          </div>
          <div style={styles.card} onClick={() => navigate('/emergency')}>
            <h3>Emergency Services</h3>
            <p>24/7 Helpline & Support</p>
          </div>
          <div style={styles.card} onClick={() => navigate('/feedback')}>
            <h3>Citizen Feedback</h3>
            <p>Share your suggestions</p>
          </div>
        </div>
      </main>
    </div>
  );
};

const styles = {
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '20px 50px',
    backgroundColor: '#3a3a50',
    color: 'white',
    boxShadow: '0 2px 10px rgba(0,0,0,0.3)'
  },
  logo: {
    fontSize: '1.5rem',
    fontWeight: 'bold'
  },
  userInfo: {
    display: 'flex',
    alignItems: 'center',
    gap: '20px'
  },
  welcomeText: {
    fontSize: '14px',
    color: '#6c63ff',
    fontWeight: 'bold'
  },
  loginBtn: {
    padding: '8px 20px',
    backgroundColor: '#6c63ff',
    color: 'white',
    border: 'none',
    borderRadius: '5px',
    cursor: 'pointer'
  },
  logoutBtn: {
    padding: '8px 20px',
    backgroundColor: '#ff4d4d',
    color: 'white',
    border: 'none',
    borderRadius: '5px',
    cursor: 'pointer'
  },
  main: {
    textAlign: 'center',
    padding: '50px 20px',
    color: '#333'
  },
  grid: {
    display: 'flex',
    justifyContent: 'center',
    gap: '20px',
    marginTop: '40px',
    flexWrap: 'wrap'
  },
  card: {
    padding: '30px',
    width: '250px',
    backgroundColor: '#f9f9f9',
    borderRadius: '10px',
    boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
    cursor: 'pointer',
    transition: 'transform 0.2s'
  }
};

export default Home;
